// ============================================================================
// BUILD REQUEST - Prepare prompt for Gemini Veo-3
// ============================================================================

const input = $input.first().json;

// Extract prompt from various possible input fields
const promptText = input.prompt_text || input.prompt || input.query || input.description || 'A beautiful cinematic video';

// Clean the prompt - remove any problematic characters
const cleanPrompt = promptText
  .replace(/[\n\r]+/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 1000); // Limit prompt length

// Optional parameters
const duration = input.duration || 5;
const hasImage = !!(input.image_base64 || input.image_url);

return [{
  json: {
    clean_prompt: cleanPrompt,
    original_prompt: promptText,
    duration: duration,
    has_image: hasImage,
    promptImage: input.image_base64 || input.image_url || null,
    promptText: cleanPrompt
  }
}];

// ============================================================================
// EXTRACT VIDEO URL FROM CATBOX RESPONSE (V2)
// ============================================================================
// Catbox retourne directement l'URL en plain text:
// https://files.catbox.moe/abc123.mp4
// ============================================================================

const response = $input.first();
const buildData = $('Build Request').item.json;

// Catbox retourne l'URL directement en texte brut
let videoUrl = null;

// Le response peut etre dans .json (si parse) ou .data (si texte brut)
if (response.json && typeof response.json === 'string') {
  videoUrl = response.json.trim();
} else if (response.data && typeof response.data === 'string') {
  videoUrl = response.data.trim();
} else if (typeof response.json === 'object' && response.json.data) {
  videoUrl = response.json.data.trim();
}

// Validation de l'URL Catbox
if (!videoUrl || !videoUrl.startsWith('https://files.catbox.moe/')) {
  console.error('Catbox response:', JSON.stringify(response));
  throw new Error('Video upload to Catbox failed. Response: ' + JSON.stringify(response));
}

return [{
  json: {
    success: true,
    video_url: videoUrl,
    provider: 'catbox',
    script: buildData.original_prompt,
    clean_prompt: buildData.clean_prompt,
    mime_type: 'video/mp4'
  }
}];

// ============================================================================
// SUCCESS OUTPUT - Format final response for Creative V6
// ============================================================================

const videoData = $input.first().json;

return [{
  json: {
    success: true,
    tool: 'veo3_video_generator',
    video: {
      url: videoData.video_url,
      script: videoData.script,
      prompt_used: videoData.clean_prompt,
      provider: videoData.provider || 'catbox',
      mime_type: videoData.mime_type,
      downloadable: true
    },
    // Pour le frontend - UI Component
    ui_component: 'AD_PREVIEW',
    ui_data: {
      video_url: videoData.video_url,
      script: videoData.script,
      title: 'Video generee par Veo-3',
      downloadable: true
    },
    // Format Creative V6
    video_url: videoData.video_url,
    prompt_used: videoData.clean_prompt,
    generated_at: new Date().toISOString()
  }
}];

// ============================================================================
// ERROR HANDLER - Format error response
// ============================================================================

const error = $input.first().json;

return [{
  json: {
    success: false,
    tool: 'veo3_video_generator',
    error: {
      message: error.message || 'Video generation failed',
      details: JSON.stringify(error)
    },
    video: null,
    generated_at: new Date().toISOString()
  }
}];
